mapper.select:
SELECT
DATE_FORMAT(create_time, '%Y-%m-%d') as date,
COUNT(*) as count,
IFNULL(SUM(duration), 0) as duration
FROM biz_meeting

    user_id = #{userId}

        AND create_time >= #{startDate}


        AND create_time <= #{endDate}


GROUP BY date
ORDER BY date ASC

SELECT CASE WHEN speaker_count = 1 THEN '单人记录' WHEN speaker_count = 2 THEN '双人对话' WHEN speaker_count BETWEEN 3 AND 5 THEN '小型会议' ELSE '大型研讨' END as name, COUNT(*) as value FROM ( SELECT c.meeting_id, COUNT(DISTINCT c.speaker) as speaker_count FROM biz_meeting_content c INNER JOIN biz_meeting m ON c.meeting_id = m.id
m.user_id = #{userId}
AND m.create_time >= #{startDate}
AND m.create_time <= #{endDate}
GROUP BY c.meeting_id ) t GROUP BY name

SELECT ai_keywords
FROM biz_meeting

    user_id = #{userId}
    AND ai_keywords IS NOT NULL
    AND ai_keywords != ''

        AND create_time >= #{startDate}


        AND create_time <= #{endDate}

SELECT DATE_FORMAT(create_time, '%Y-%m-%d') as date, COUNT(*) as count, IFNULL(SUM(duration), 0) as duration FROM biz_meeting
AND create_time >= #{startDate}
AND create_time <= #{endDate}
GROUP BY date ORDER BY date ASC

SELECT CASE WHEN speaker_count = 1 THEN '单人记录' WHEN speaker_count = 2 THEN '双人对话' WHEN speaker_count BETWEEN 3 AND 5 THEN '小型会议' ELSE '大型研讨' END as name, COUNT(*) as value FROM ( SELECT c.meeting_id, COUNT(DISTINCT c.speaker) as speaker_count FROM biz_meeting_content c INNER JOIN biz_meeting m ON c.meeting_id = m.id
AND m.create_time >= #{startDate}
AND m.create_time <= #{endDate}
GROUP BY c.meeting_id ) t GROUP BY name

SELECT ai_keywords FROM biz_meeting

    ai_keywords IS NOT NULL AND ai_keywords != ''

        AND create_time >= #{startDate}


        AND create_time <= #{endDate}

SELECT IFNULL(AVG(asr_duration), 0) as avgAsrDuration, IFNULL(AVG(llm_duration), 0) as avgLlmDuration FROM biz_meeting
status = 4 AND asr_duration > 0
AND create_time >= #{startDate}
AND create_time <= #{endDate}

SELECT
IFNULL(t.name, '未分类') as name,
COUNT(m.id) as value
FROM biz_meeting m
LEFT JOIN sys_topic_library t ON m.topic_library_id = t.id

    m.user_id = #{userId}

        AND m.create_time >= #{startDate}


        AND m.create_time <= #{endDate}


GROUP BY m.topic_library_id, t.name

SELECT IFNULL(t.name, '未分类') as name, COUNT(m.id) as value FROM biz_meeting m LEFT JOIN sys_topic_library t ON m.topic_library_id = t.id
AND m.create_time >= #{startDate}
AND m.create_time <= #{endDate}
GROUP BY m.topic_library_id, t.name
